// File: init.php // Get custom editor settings. $settings = getdave_sbe_get_block_editor_settings(); // Inline all settings. wp_add_inline_script( $script_handle, 'window.getdaveSbeSettings = ' . wp_json_encode( $settings ) . ';' );
