export function* saveRecordAction( id ) { const record = yield controls.select( 'current-store', 'getRecord', id ); yield { type: 'BEFORE_SAVE', id, record }; const results = yield controls.fetch({ url: 'https://...', method: 'POST', data: record }); yield { type: 'AFTER_SAVE', id, results }; return results; } const controls = { select: // ..., fetch: // ..., };
Side effects like store operations and fetch functions would be implemented outside of the action. Thunks provide an alternative to this approach. They allow you to use side effects inline, like this:
export const saveRecordAction = ( id ) => async ({ select, dispatch }) => { const record = select( 'current-store', 'getRecord', id ); dispatch({ type: 'BEFORE_SAVE', id, record }); const response = await fetch({ url: 'https://...', method: 'POST', data: record }); const results = await response.json(); dispatch({ type: 'AFTER_SAVE', id, results }); return results; }
export const saveRecordAction = ( id ) => async ({ select, dispatch }) => { const record = select( 'current-store', 'getRecord', id ); dispatch({ type: 'BEFORE_SAVE', id, record }); const response = await fetch({ url: 'https://...', method: 'POST', data: record }); const results = await response.json(); dispatch({ type: 'AFTER_SAVE', id, results }); return results; }
This removes the need to implement separate controls.
### Thunks have access to the store helpers
Let’s take a look at an example from Gutenberg core. Prior to thunks, the toggleFeature action from the @wordpress/interface package was implemented like this:
toggleFeature
@wordpress/interface

const store = wp.data.createReduxStore( 'my-store', { actions: { saveTemperatureToAPI: function*( temperature ) { const result = yield { type: 'FETCH_JSON', url: 'https://...', method: 'POST', data: { temperature } }; return result; } }, controls: { async FETCH_JSON( action ) { const response = await window.fetch( action.url, { method: action.method, body: JSON.stringify( action.data ), } ); return response.json(); } }, // reducers, selectors, ... } );
const store = wp.data.createReduxStore( 'my-store', { actions: { saveTemperatureToAPI: function*( temperature ) { const result = yield { type: 'FETCH_JSON', url: 'https://...', method: 'POST', data: { temperature } }; return result; } }, controls: { async FETCH_JSON( action ) { const response = await window.fetch( action.url, { method: action.method, body: JSON.stringify( action.data ), } ); return response.json(); } }, // reducers, selectors, ... } );
While the code is reasonably straightforward, there is a level of indirection. The saveTemperatureToAPI action does not talk directly to the API, but has to go through the FETCH_JSON control.
saveTemperatureToAPI
FETCH_JSON
Let’s see how this indirection can be removed with thunks:
const store = wp.data.createReduxStore( 'my-store', { actions: { saveTemperatureToAPI: ( temperature ) => async () => { const response = await window.fetch( 'https://...', { method: 'POST', body: JSON.stringify( { temperature } ), } ); return await response.json(); } }, // reducers, selectors, ... } );

const thunk = () => ( { select } ) => { // select is an object of the store’s selectors, pre-bound to current state: const temperature = select.getTemperature(); }
const thunk = () => ( { select } ) => { // select is an object of the store’s selectors, pre-bound to current state: const temperature = select.getTemperature(); }
Since not all selectors are exposed on the store, select doubles as a function that supports passing a selector as an argument:
select
const thunk = () => ( { select } ) => { // select supports private selectors: const doubleTemperature = select( ( temperature ) => temperature * 2 ); }
const thunk = () => ( { select } ) => { // select supports private selectors: const doubleTemperature = select( ( temperature ) => temperature * 2 ); }
### resolveSelect
resolveSelect is the same as select, except it returns a promise that resolves with the value provided by the related resolver.
resolveSelect
select
const thunk = () => ( { resolveSelect } ) => { const temperature = await resolveSelect.getTemperature(); }
const thunk = () => ( { resolveSelect } ) => { const temperature = await resolveSelect.getTemperature(); }
### dispatch
An object containing the store’s actions
If an action is part of the public API, it’s available as a method on the dispatch object:
dispatch
const thunk = () => ( { dispatch } ) => { // dispatch is an object of the store’s actions: const temperature = await dispatch.retrieveTemperature(); }
const thunk = () => ( { dispatch } ) => { // dispatch is an object of the store’s actions: const temperature = await dispatch.retrieveTemperature(); }
Since not all actions are exposed on the store, dispatch doubles as a function that supports passing a Redux action as an argument:
dispatch

